    37|// In-memory store (persisted to Redis in production via the worker)
    38|const requestStore = new Map<string, RequestRecord>();
    39|const idempotencyIndex = new Map<string, string>(); // idempotencyKey → traceId
    40|
    41|const MAX_STORE_SIZE = 1000;
    42|
    43|function pruneStore(): void {
    44|  if (requestStore.size > MAX_STORE_SIZE) {
    45|    const oldestKeys = Array.from(requestStore.keys())
    46|      .slice(0, requestStore.size - MAX_STORE_SIZE);
    47|    for (const key of oldestKeys) {
    48|      const record = requestStore.get(key);
    49|      if (record) {
    50|        idempotencyIndex.delete(record.idempotencyKey);
    51|      }
    52|      requestStore.delete(key);
    53|    }
    54|  }
