    65|function generateIdempotencyKey(conversationId: string, message: string): string {
    66|  let hash = 0;
    67|  const input = `${conversationId}:${message}`;
    68|  for (let i = 0; i < input.length; i++) {
    69|    const char = input.charCodeAt(i);
    70|    hash = ((hash << 5) - hash + char) | 0;
    71|  }
    72|  return `idemp-${Math.abs(hash).toString(36)}-${input.length.toString(36)}`;
